const output = $input.first().json.output || '';

const replyMatch = output.match(/REPLY:\s*([\s\S]*?)(?=\nDATA:|$)/);
const reply = replyMatch ? replyMatch[1].trim() : output.trim();

const dataMatch = output.match(/DATA:\s*(\{[\s\S]*?\}\s*$|\{[\s\S]*?\}(?=\n))/);
let data = {};
if (dataMatch) {
  try {
    data = JSON.parse(dataMatch[1].trim());
  } catch(e) {
    const jsonMatch = output.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { data = JSON.parse(jsonMatch[0]); } catch(e2) {}
    }
  }
}

const stage = parseInt(data['стадия'] || 0);
const hasContact = !!(data['контакт'] && data['контакт'].toString().length > 2);
const chatId = $('Telegram Trigger').item.json.message.chat.id;
const userName = $('Telegram Trigger').item.json.message.from?.first_name || '';

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const date = pad(now.getDate()) + '.' + pad(now.getMonth() + 1) + '.' + now.getFullYear();
const time = pad(now.getHours()) + ':' + pad(now.getMinutes());

const safe = (val) => {
  if (val === null || val === undefined) return '';
  const s = String(val).trim();
  return ['=', '+', '-', '@'].includes(s[0]) ? "'" + s : s;
};

const interests = Array.isArray(data['интересы'])
  ? data['интересы'].join(', ')
  : (data['интересы'] || '');

return [{
  json: {
    reply, data, stage, hasContact, chatId, userName,
    sheets: {
      date, time,
      name:      safe(data['имя'] || userName),
      contact:   safe(data['контакт']),
      ageGroup:  safe(data['возрастная_группа']),
      interests: safe(interests),
      format:    safe(data['предпочтительный_формат']),
      timePref:  safe(data['предпочтительное_время']),
      whoGoes:   safe(data['кто_ходит']),
      willPay:   safe(data['готовность_платить']),
      event:     safe(data['рекомендованное_событие'])
    }
  }
}];
